data.content:
MSTest **does not have** `Assert.IsGreaterThan`, `Assert.IsInRange`, or similar comparison assertions. Here's what to use instead:

### Your options

**1. Standard `Assert.IsTrue` with a condition** (built-in):
```csharp
Assert.IsTrue(percentage >= 0.0);
Assert.IsTrue(percentage <= 100.0);
```

**2. `Assert.That` fluent syntax** (MSTest v3.8+):
```csharp
Assert.That.Value(percentage).Satisfies(p => p >= 0.0 && p <= 100.0);
```

**3. Use FluentAssertions** (recommended for readability):
```csharp
percentage.Should().BeGreaterThanOrEqualTo(0.0);
percentage.Should().BeInRange(0.0, 100.0);
```

### Example tests for your code

```csharp
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace Contoso.Scoring.Tests;

[TestClass]
public class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calc = new();

    [TestMethod]
    public void CalculatePercentage_PerfectScore_Returns100()
    {
        double result = _calc.CalculatePercentage(10, 10);
        Assert.AreEqual(100.0, result);
    }

    [TestMethod]
    public void CalculatePercentage_Result_IsInValidRange()
    {
        double result = _calc.CalculatePercentage(7, 10);
        Assert.IsTrue(result >= 0.0 && result <= 100.0,
            $"Expected 0–100 but got {result}");
    }

    [TestMethod]
    public void NormalizeScore_ExceedsMax_CapsAt100()
    {
        double result = _calc.NormalizeScore(150, 100);
        Assert.AreEqual(100.0, result);
        Assert.IsTrue(result <= 100.0);
    }

    [TestMethod]
    public void GetGrade_BoundaryValues_ReturnsCorrectGrade()
    {
        Assert.AreEqual("A", _calc.GetGrade(90.0));   // lower bound of A
        Assert.AreEqual("B", _calc.GetGrade(89.99));   // just below A
        Assert.AreEqual("B", _calc.GetGrade(80.0));    // lower bound of B
        Assert.AreEqual("F", _calc.GetGrade(59.99));   // just below D
    }

    [TestMethod]
    public void CalculatePercentage_ZeroTotal_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(0, 0));
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(-1, 10));
    }

    [TestMethod]
    public void CalculatePercentage_CorrectExceedsTotal_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(11, 10));
    }
}
```

**Key takeaway:** For numeric comparisons in MSTest, use `Assert.IsTrue(condition, message)` with a descriptive failure message. If you want richer assertion syntax, add the **FluentAssertions** NuGet package.
